#include <iostream>
#include <string>

using namespace std;

int main() {
    string s;
    getline(cin, s);

    int length = 0;
    int i = s.length() - 1;

    while (i >= 0 && s[i] == ' ') {
        i--;
    }

    while (i >= 0 && s[i] != ' ') {
        length++;
        i--;
    }
    cout << length << endl;

    return 0;
}

code.C:
#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MAX_LEN 100005

int main() {
    char s[MAX_LEN];

    if (fgets(s, sizeof(s), stdin) == NULL) {
        printf("0\n");
        return 0;
    }

    int length = 0;
    int i = strlen(s) - 1;

    while (i >= 0 && isspace(s[i])) {
        i--;
    }

    while (i >= 0 && !isspace(s[i])) {
        length++;
        i--;
    }

    printf("%d\n", length);
    return 0;
}

